INSERT INTO `news` (`id`, `topic`, `slug`, `content`, `image`, `created_at`, `updated_at`) VALUES
(1, 'رهّاب التاريخ والحكومة الفاشية', 'رهّاب-التاريخ-والحكومة-الفاشية-1', 'كنادفرمبا: أصدرت مجلة الكنوز -مجلة للصغار- بأيادي السادة سيد الأمة السيد صادق علي شهاب و السيد بشير علي شهاب في ١٨ يناير، و أصدرت مجلة الكنوز تحت قيادة مجلة المداد حيث فتحت بوابة للأدباء الصغارالذين يجدون من الكتابة في اللغة العربية، وقد أسرعت لجنة مجلة المداد التي تصدر من كلية دار الحسنات الإسلامية إصدار الكنوز عقب إصدار «المداد» قبل شهرين. وفي بداية المداد كان الطلاب يشتاقون و يستقيمون أقلامهم في كتابة اللغة العربية إلى مجلة المداد حيث لما كثر صفحاتهم وجد لجنة المداد إلى تكوين و تصدير مجلة جديدة مخصوصة للأطفال و لأقلامهم حتى سيصير الكنوز بوابة متطورة للأدباء الصغار من الكليات. وقال محرر مجلة الكنوز : اليوم نحن فتحنا حديقة للأطفال الصغار و \nكنادفرمبا: أصدرت مجلة الكنوز -مجلة للصغار- بأيادي السادة سيد الأمة السيد صادق علي شهاب و السيد بشير علي شهاب في ١٨ يناير، و أصدرت مجلة الكنوز تحت قيادة مجلة المداد حيث فتحت بوابة للأدباء الصغارالذين يجدون من الكتابة في اللغة العربية، وقد أسرعت لجنة مجلة المداد التي تصدر من كلية دار الحسنات الإسلامية إصدار الكنوز عقب إصدار «المداد» قبل شهرين. وفي بداية المداد كان الطلاب يشتاقون و يستقيمون أقلامهم في كتابة اللغة العربية إلى مجلة المداد حيث لما كثر صفحاتهم وجد لجنة المداد إلى تكوين و تصدير مجلة جديدة مخصوصة للأطفال و لأقلامهم حتى سيصير الكنوز بوابة متطورة للأدباء الصغار من الكليات. وقال محرر مجلة الكنوز : اليوم نحن فتحنا حديقة للأطفال الصغار و \nمقصدنا بهذا إبلاغ الأطفال إلى قمة اللغة و تطوير مهاراتهم في كل مجال اللغة و المطلوب من الأطفال أن يرسلوا إلينا براعاتهم خلال البريد الإلكتروني ليفتح أمامهم مستقبل زاهر.كنادفرمبا: أصدرت مجلة الكنوز -مجلة للصغار- بأيادي السادة سيد الأمة السيد صادق علي شهاب و السيد بشير علي شهاب في ١٨ يناير، و أصدرت مجلة الكنوز تحت قيادة مجلة المداد حيث فتحت بوابة للأدباء الصغارالذين يجدون من الكتابة في اللغة العربية، وقد أسرعت لجنة مجلة المداد التي تصدر من كلية دار الحسنات الإسلامية إصدار الكنوز عقب إصدار «المداد» قبل شهرين. وفي بداية المداد كان الطلاب يشتاقون و يستقيمون أقلامهم في كتابة اللغة العربية إلى مجلة المداد حيث لما كثر صفحاتهم وجد لجنة المداد إلى تكوين و تصدير مجلة جديدة مخصوصة للأطفال و لأقلامهم حتى سيصير الكنوز بوابة متطورة للأدباء الصغار من الكليات. وقال محرر مجلة الكنوز : اليوم نحن فتحنا حديقة للأطفال الصغار و \nمقصدنا بهذا إبلاغ الأطفال إلى قمة اللغة و تطوير مهاراتهم في كل مجال اللغة و المطلوب من الأطفال أن يرسلوا إلينا براعاتهم خلال البريد الإلكتروني ليفتح أمامهم مستقبل زاهر.مقصدنا بهذا إبلاغ الأطفال إلى قمة اللغة و تطوير مهاراتهم في كل مجال اللغة و المطلوب من الأطفال أن يرسلوا إلينا براعاتهم خلال البريد الإلكتروني ليفتح أمامهم مستقبل زاهر.', 'news/01JS4FJVE6BPTZAZA33PJ5K53A.jpg', '2025-11-16 16:31:59', '2025-11-16 16:31:59'),
(2, 'رهّاب التاريخ والحكومة الفاشية', 'رهّاب-التاريخ-والحكومة-الفاشية', 'امتاز حفل الافتتاح لجمعية الطلبة «أحساس» مع إحاطة النبلاء ضيوفا. الغرض من هذا الاجتماع هو بدء أنشطة المنظمة وخلق شعور بالهدف المنظمة لتكون نشطة في العام المقبل. أجرى الحفل في المسجد بحضور رئيس الكلية السيد علي هاشم الندوي، محمد شاهد موظف يعمل في الخدمة المدنية، أعضاء اللجنة الموقرين للكلية والأساتيذ الأعزة. ذكر السيد أن قوة المنظمة هي الأقوى ويجب أن يكون لدى من أوكلت إليهم مسؤوليتها التطور والإشعار بأن أكتافهم على أمانة الله فعليهم أن يقودوا المنظمة دون أن يقصروا. وفي محاضرته الإفتتاحية، حث السيد الطلبة على أخذ نماذج يُقتدى بها في هذا الشأن المهتم مع تأكيد توارخ للعلماء السابقين الذين يقودون المنظمات. جاء الأساتيذ في خطاباتهم الترحيبية بأمثلة على أن دور المنظمة في التنمية الشخصية كبير جدا، والذين عملوا في مثل هذه المنظمات خلال فترة الدراسة أصبحوا فيما بعد ناشطين فعّالين. خاطب الإجتماعَ الضيفُ الجليلُ محمد شاهد بالتجارب الواقعية خلال فترة دراسة الخدمة الوطنية مع توضيح المواقع وترشيح المواضع كاشدها، وكان معظم خطبته عن التطور الفردي. أضاف قائلاً: إنني مثلك بدأت دراستي راغبا في أن أصبح هدويا، لكنني لم أستطع ذلك لأسباب شتى، ومع ذلك، كنت مشغوفا بالأمور السياسية الهندية منذ صغري وبعد الإنتهاء من الدراسة، ركزت على الخدمة المدنية. أضاف متعلقا أن الوقت الآتي مناسب لموظف حكومي لوضع حد للفظائع ضد الأقليات مثل المسلمين وقد واجهت العديد من الهزائم في حياتي لتحقيق هذا العمل الفذ. ومن الجدير بالذكر، فتحت هذه التجارب مساليك جديدة للخدمات المدنية مثل الخدمات المدنية الإقليمية والخدمات الإدارية الهندية بين الطلاب تدرجا. وأشار إلى أن المضايق قد تعق الحياة يجب مواجهتها مباشرة بشجاعة.', 'news/01K8AXT8322BRWAYBG9E41SR58.JPG', '2025-11-16 16:31:59', '2025-11-16 16:31:59');

